"use client";

import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import {
  Heart,
  MapPin,
  Building2,
  Star,
  Activity,
  Bed,
  CheckCircle2,
  Phone,
  Shield,
  Loader2,
  ArrowLeft,
  DollarSign,
  User,
  Clock,
  MessageSquare,
  BadgeAlert,
  Calendar,
} from "lucide-react";
import Link from "next/link";

interface BedInventory {
  id: string;
  type: string;
  total: number;
  available: number;
  pricePerDay: number;
}

interface Doctor {
  id: string;
  name: string;
  specialization: string;
  qualification: string;
  experience: number;
  consultationFee: number;
  bio: string | null;
  isAvailable: boolean;
  slots: { id: string; date: string; startTime: string; endTime: string }[];
}

interface TreatmentCost {
  id: string;
  treatmentName: string;
  department: string;
  minCost: number;
  maxCost: number;
  insuranceCovered: boolean;
  description: string | null;
}

interface Review {
  id: string;
  rating: number;
  comment: string | null;
  createdAt: string;
  patient: {
    name: string;
  };
}

interface Hospital {
  id: string;
  name: string;
  phone: string;
  email: string;
  description: string;
  address: string;
  city: string;
  state: string;
  pincode: string;
  isOpen24Hours: boolean;
  acceptedInsurances: string[];
  avgRating: number;
  totalRatings: number;
  specializations: { name: string }[];
  beds: BedInventory[];
  doctors: Doctor[];
  treatmentCosts: TreatmentCost[];
  reviews: Review[];
}

export default function HospitalProfilePage() {
  const router = useRouter();
  const { id } = useParams() as { id: string };
  const [hospital, setHospital] = useState<Hospital | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<"overview" | "doctors" | "pricing" | "reviews">("overview");

  useEffect(() => {
    async function fetchHospitalDetails() {
      try {
        setLoading(true);
        const res = await fetch(`/api/hospitals/${id}`);
        const data = await res.json();
        if (data.success) {
          setHospital(data.data);
        } else {
          setHospital(null);
        }
      } catch (err) {
        console.error("Error fetching hospital details:", err);
      } finally {
        setLoading(false);
      }
    }

    if (id) {
      fetchHospitalDetails();
    }
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
          <p className="text-text-secondary text-sm">Loading hospital profile...</p>
        </div>
      </div>
    );
  }

  if (!hospital) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-surface-secondary text-center px-4">
        <BadgeAlert className="w-12 h-12 text-error mb-4" />
        <h1 className="text-2xl font-bold text-text-primary mb-2">Hospital Not Found</h1>
        <p className="text-text-secondary mb-6">
          The hospital profile you are trying to view does not exist or has been removed.
        </p>
        <button
          onClick={() => router.push("/hospitals")}
          className="inline-flex items-center gap-2 px-5 py-2.5 bg-primary-600 hover:bg-primary-700 text-white font-semibold rounded-xl transition-all"
        >
          <ArrowLeft className="w-4 h-4" /> Back to Search
        </button>
      </div>
    );
  }

  const totalBeds = hospital.beds?.reduce((sum, b) => sum + b.total, 0) || 0;
  const availableBeds = hospital.beds?.reduce((sum, b) => sum + b.available, 0) || 0;

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header Banner */}
      <header className="bg-white border-b border-border sticky top-0 z-50 shadow-xs">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/hospitals")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <div className="w-8 h-8 gradient-bg rounded-lg flex items-center justify-center">
              <Heart className="w-4.5 h-4.5 text-white" />
            </div>
            <span className="text-lg font-bold gradient-text">HealthBridge</span>
          </div>
          <span className="text-xs px-2.5 py-1 bg-emerald-50 text-emerald-700 border border-emerald-200 rounded-full font-semibold">
            {hospital.isOpen24Hours ? "Open 24/7" : "Open during clinic hours"}
          </span>
        </div>
      </header>

      {/* Main Profile Info Section */}
      <div className="bg-white border-b border-border py-8 mb-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
            <div>
              <h1 className="text-2xl sm:text-3xl font-extrabold text-text-primary flex items-center gap-2">
                <Building2 className="w-8 h-8 text-primary-600 hidden sm:inline" />
                {hospital.name}
              </h1>
              
              <div className="flex flex-wrap items-center gap-y-2 gap-x-4 mt-3 text-sm text-text-secondary">
                <span className="flex items-center gap-1.5">
                  <MapPin className="w-4 h-4 text-text-muted" />
                  {hospital.address}, {hospital.city}, {hospital.state}
                </span>
                <span className="flex items-center gap-1.5">
                  <Phone className="w-4 h-4 text-text-muted" />
                  {hospital.phone}
                </span>
              </div>

              <div className="flex flex-wrap gap-1.5 mt-4">
                {hospital.specializations.map((spec) => (
                  <span
                    key={spec.name}
                    className="text-xs px-2.5 py-1 bg-primary-50 text-primary-700 rounded-lg font-medium"
                  >
                    {spec.name}
                  </span>
                ))}
              </div>
            </div>

            {/* Overall stats board */}
            <div className="flex items-center gap-4">
              <div className="bg-surface-secondary border border-border rounded-2xl px-5 py-4 text-center min-w-28">
                <div className="flex items-center justify-center gap-1 text-amber-700 font-bold text-lg">
                  <Star className="w-5 h-5 fill-amber-500 text-amber-500" />
                  <span>{hospital.avgRating.toFixed(1)}</span>
                </div>
                <span className="text-xs text-text-muted mt-1 block">({hospital.totalRatings} ratings)</span>
              </div>

              <div className="bg-surface-secondary border border-border rounded-2xl px-5 py-4 text-center min-w-28">
                <div className="text-emerald-700 font-bold text-lg">
                  {availableBeds} / {totalBeds}
                </div>
                <span className="text-xs text-text-muted mt-1 block">Beds Available</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Profile Details Container */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid lg:grid-cols-3 gap-8 items-start">
          {/* Main Content Column */}
          <div className="lg:col-span-2 space-y-6">
            {/* Tabs */}
            <div className="flex border-b border-border bg-white rounded-t-2xl px-4 pt-2">
              {(
                [
                  { id: "overview", label: "Overview" },
                  { id: "doctors", label: "Doctors" },
                  { id: "pricing", label: "Pricing & Services" },
                  { id: "reviews", label: "Reviews" },
                ] as const
              ).map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`px-4 py-3 text-sm font-semibold border-b-2 cursor-pointer transition-colors -mb-px ${
                    activeTab === tab.id
                      ? "border-primary-600 text-primary-600"
                      : "border-transparent text-text-secondary hover:text-text-primary"
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>

            {/* Tab Panels */}
            <div className="bg-white border border-t-0 border-border rounded-b-2xl p-6">
              {activeTab === "overview" && (
                <div className="space-y-6">
                  {/* About */}
                  <div>
                    <h3 className="text-base font-bold text-text-primary mb-2">About the Hospital</h3>
                    <p className="text-sm text-text-secondary leading-relaxed">{hospital.description}</p>
                  </div>

                  {/* Bed Status details */}
                  <div>
                    <h3 className="text-base font-bold text-text-primary mb-3">Live Bed Inventory</h3>
                    <div className="grid sm:grid-cols-2 gap-4">
                      {hospital.beds.map((bed) => (
                        <div key={bed.id} className="border border-border rounded-xl p-4 flex justify-between items-center bg-surface-secondary/50">
                          <div>
                            <span className="text-sm font-bold text-text-primary block capitalize">{bed.type.replace("_", " ").toLowerCase()} Bed</span>
                            <span className="text-xs text-text-muted mt-1 block">₹{bed.pricePerDay.toLocaleString("en-IN")} / day</span>
                          </div>
                          <div className="text-right">
                            <span className={`text-sm font-bold block ${bed.available > 0 ? "text-emerald-600" : "text-error"}`}>
                              {bed.available} Available
                            </span>
                            <span className="text-xs text-text-muted block">out of {bed.total} total</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Insurance accepted list */}
                  <div>
                    <h3 className="text-base font-bold text-text-primary mb-3">Accepted Insurances</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                      {hospital.acceptedInsurances.map((ins) => (
                        <div key={ins} className="border border-border rounded-xl p-3 flex items-center gap-2 bg-white">
                          <CheckCircle2 className="w-4 h-4 text-emerald-500 flex-shrink-0" />
                          <span className="text-xs font-semibold text-text-primary">{ins}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {activeTab === "doctors" && (
                <div className="space-y-6">
                  <h3 className="text-base font-bold text-text-primary">Medical Specialists</h3>
                  {hospital.doctors.length === 0 ? (
                    <div className="text-center py-10 text-text-muted">
                      <User className="w-10 h-10 mx-auto mb-2 opacity-50" />
                      <p className="text-sm">No doctors currently onboarded at this facility.</p>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {hospital.doctors.map((doctor) => (
                        <div key={doctor.id} className="border border-border rounded-xl p-5 flex flex-col md:flex-row justify-between gap-4">
                          <div className="space-y-2">
                            <div>
                              <h4 className="text-base font-bold text-text-primary">{doctor.name}</h4>
                              <p className="text-xs font-semibold text-primary-600 mt-0.5">{doctor.specialization} • {doctor.qualification}</p>
                            </div>
                            <p className="text-xs text-text-secondary leading-relaxed">{doctor.bio || "No biography provided."}</p>
                            <div className="flex items-center gap-4 text-xs text-text-muted pt-1">
                              <span>Experience: <strong>{doctor.experience} Years</strong></span>
                              <span>Offline Consult Fee: <strong>₹{doctor.consultationFee}</strong></span>
                            </div>
                          </div>

                          <div className="flex-shrink-0 flex flex-col justify-center items-start md:items-end gap-3 pt-4 md:pt-0 border-t md:border-t-0 border-border">
                            {doctor.slots.length > 0 ? (
                              <button
                                onClick={() => router.push(`/appointments/new?hospital=${hospital.id}&doctor=${doctor.id}`)}
                                className="px-4 py-2 bg-primary-600 hover:bg-primary-700 text-white font-semibold text-xs rounded-xl shadow-xs transition-all flex items-center gap-1.5 cursor-pointer"
                              >
                                <Calendar className="w-3.5 h-3.5" /> Book Consultation
                              </button>
                            ) : (
                              <span className="text-xs text-warning bg-amber-50 px-2.5 py-1 rounded-lg border border-amber-200 font-medium">
                                No slots available
                              </span>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {activeTab === "pricing" && (
                <div className="space-y-6">
                  <h3 className="text-base font-bold text-text-primary">Treatment Cost Catalog</h3>
                  {hospital.treatmentCosts.length === 0 ? (
                    <div className="text-center py-10 text-text-muted">
                      <DollarSign className="w-10 h-10 mx-auto mb-2 opacity-50" />
                      <p className="text-sm">Treatment costs catalog is not available for this hospital.</p>
                    </div>
                  ) : (
                    <div className="overflow-x-auto border border-border rounded-xl">
                      <table className="w-full text-left border-collapse">
                        <thead>
                          <tr className="bg-surface-secondary border-b border-border">
                            <th className="p-3 text-xs font-bold text-text-primary uppercase tracking-wider">Treatment / Procedure</th>
                            <th className="p-3 text-xs font-bold text-text-primary uppercase tracking-wider">Department</th>
                            <th className="p-3 text-xs font-bold text-text-primary uppercase tracking-wider">Est. Cost Range</th>
                            <th className="p-3 text-xs font-bold text-text-primary uppercase tracking-wider">Insurance Covered</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-border text-sm">
                          {hospital.treatmentCosts.map((cost) => (
                            <tr key={cost.id} className="hover:bg-surface-secondary/35">
                              <td className="p-3 font-semibold text-text-primary">
                                <div>{cost.treatmentName}</div>
                                {cost.description && <div className="text-xs text-text-muted mt-0.5 font-normal">{cost.description}</div>}
                              </td>
                              <td className="p-3 text-text-secondary">{cost.department}</td>
                              <td className="p-3 font-bold text-text-primary">₹{cost.minCost.toLocaleString("en-IN")} - ₹{cost.maxCost.toLocaleString("en-IN")}</td>
                              <td className="p-3">
                                {cost.insuranceCovered ? (
                                  <span className="text-xs px-2 py-0.5 bg-emerald-50 text-emerald-700 rounded-md font-semibold">Yes</span>
                                ) : (
                                  <span className="text-xs px-2 py-0.5 bg-surface-secondary text-text-muted rounded-md font-medium">No</span>
                                )}
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              )}

              {activeTab === "reviews" && (
                <div className="space-y-6">
                  <h3 className="text-base font-bold text-text-primary">Patient Feedback</h3>
                  {hospital.reviews.length === 0 ? (
                    <div className="text-center py-10 text-text-muted">
                      <MessageSquare className="w-10 h-10 mx-auto mb-2 opacity-50" />
                      <p className="text-sm">No reviews posted yet.</p>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {hospital.reviews.map((review) => (
                        <div key={review.id} className="border border-border rounded-xl p-4 bg-surface-secondary/25">
                          <div className="flex items-center justify-between mb-2">
                            <span className="font-semibold text-sm text-text-primary">{review.patient.name}</span>
                            <div className="flex items-center gap-0.5 text-amber-500 text-xs font-semibold">
                              {Array.from({ length: 5 }).map((_, i) => (
                                <Star
                                  key={i}
                                  className={`w-3.5 h-3.5 ${
                                    i < review.rating ? "fill-amber-500 text-amber-500" : "text-border"
                                  }`}
                                />
                              ))}
                            </div>
                          </div>
                          <p className="text-xs sm:text-sm text-text-secondary leading-relaxed">{review.comment || "Left rating only."}</p>
                          <span className="text-[10px] text-text-muted mt-2 block">
                            Posted on {new Date(review.createdAt).toLocaleDateString()}
                          </span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          {/* Quick Action Side Panel */}
          <div className="bg-white border border-border rounded-2xl p-6 space-y-6 lg:sticky lg:top-24">
            <h3 className="font-bold text-lg text-text-primary border-b border-border pb-3">Quick Support</h3>
            
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-primary-50 flex items-center justify-center flex-shrink-0">
                  <Phone className="w-5 h-5 text-primary-600" />
                </div>
                <div>
                  <span className="text-xs text-text-muted block">Emergency Contact</span>
                  <a href={`tel:${hospital.phone}`} className="text-sm font-bold text-text-primary hover:text-primary-700 transition-colors">
                    {hospital.phone}
                  </a>
                </div>
              </div>

              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-accent-50 flex items-center justify-center flex-shrink-0">
                  <Building2 className="w-5 h-5 text-accent-600" />
                </div>
                <div>
                  <span className="text-xs text-text-muted block">Email Support</span>
                  <a href={`mailto:${hospital.email}`} className="text-sm font-semibold text-text-primary hover:text-primary-700 transition-colors">
                    {hospital.email}
                  </a>
                </div>
              </div>
            </div>

            <button
              onClick={() => {
                if (hospital.doctors.length > 0) {
                  router.push(`/appointments/new?hospital=${hospital.id}`);
                } else {
                  alert("No doctors onboarded. Please check again later.");
                }
              }}
              className="w-full py-3 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-xl transition-all shadow-xs flex items-center justify-center gap-2 cursor-pointer text-sm"
            >
              <Calendar className="w-4 h-4" /> Book Appointment
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
